const body = $json.body || $json;
const data = body.data || body;
const key = data.key || {};
const message = data.message || {};

const remoteJid = key.remoteJid || data.remoteJid || data.from || body.from || '';
const instance = body.instance || data.instance || $env.EVOLUTION_INSTANCE || 'default';
const messageId = key.id || data.messageId || body.messageId || `${Date.now()}-${remoteJid}`;

let text = '';
let messageType = 'unknown';
let mediaUrl = '';
let caption = '';

if (message.conversation) {
  text = message.conversation;
  messageType = 'text';
} else if (message.extendedTextMessage?.text) {
  text = message.extendedTextMessage.text;
  messageType = 'text';
} else if (message.audioMessage) {
  messageType = 'audio';
  mediaUrl = message.audioMessage.url || data.mediaUrl || data.url || '';
} else if (message.imageMessage) {
  messageType = 'image';
  mediaUrl = message.imageMessage.url || data.mediaUrl || data.url || '';
  caption = message.imageMessage.caption || data.caption || '';
  text = caption;
} else if (data.messageType) {
  const mt = String(data.messageType).toLowerCase();
  if (mt === 'conversation' || mt === 'extendedtextmessage' || mt === 'text') {
    messageType = 'text';
    text = data.text || data.body || '';
  } else if (mt.includes('audio')) {
    messageType = 'audio';
    mediaUrl = data.mediaUrl || data.url || '';
  } else if (mt.includes('image')) {
    messageType = 'image';
    mediaUrl = data.mediaUrl || data.url || '';
    caption = data.caption || '';
    text = caption;
  } else {
    messageType = mt;
    text = data.text || data.body || '';
  }
}

return [{
  json: {
    raw: body,
    event: body.event || data.event || '',
    instance,
    remoteJid,
    messageId,
    messageType,
    text: String(text || '').trim(),
    mediaUrl,
    caption,
    isFromMe: Boolean(key.fromMe)
  }
}];

const original = $('Normalizar mensagem').first().json;
const text = String(original.text || '').trim();

const catalogRegex = /(pre[çc]o|valor|tem|vende|produto|cat[aá]logo|copo|copos|embalagem|embalagens|prato|pratos|talher|talheres|guardanapo|delivery|marmita|isopor|sacola|descart[aá]vel)/i;
const route = catalogRegex.test(text) ? 'catalogo' : 'atendimento';

return [{
  json: {
    ...original,
    route,
    termoBusca: text,
    limite: 5
  }
}];

const produtos = $input.all().map(i => i.json);
const original = $('Classificar texto').first().json;

let resposta;
if (!produtos.length) {
  resposta = 'Não encontrei esse item no catálogo agora. Posso verificar com a equipe para confirmar disponibilidade e preço?';
} else {
  resposta = 'Encontrei estes produtos no catálogo:\n\n' + produtos.map((p, idx) => {
    const preco = p.price !== undefined && p.price !== null ? ` - R$ ${Number(p.price).toFixed(2)}` : '';
    return `${idx + 1}. ${p.name}${preco}\n${p.description || ''}${p.image_url ? `\nImagem: ${p.image_url}` : ''}`;
  }).join('\n\n') + '\n\nPosso ajudar em mais alguma coisa?';
}

return [{ json: { instance: original.instance, remoteJid: original.remoteJid, messageId: original.messageId, resposta } }];

const original = $('Classificar texto').first().json;
const historico = $input.all().map(i => i.json).reverse()
  .map(m => `${m.sender_type === 'agent' ? 'Atendente' : 'Cliente'}: ${m.content}`)
  .join('\n');

return [{
  json: {
    ...original,
    promptUsuario: `Histórico recente:\n${historico || '(sem histórico)'}\n\nMensagem atual do cliente: ${original.text}`
  }
}];

