const original = $('Preparar prompt com histórico').first().json;
const resposta =
  $json.choices?.[0]?.message?.content ||
  $json.message?.content ||
  $json.text ||
  $json.output ||
  'Desculpe, não consegui gerar uma resposta agora. Vou verificar com a equipe.';

return [{ json: { instance: original.instance, remoteJid: original.remoteJid, messageId: original.messageId, resposta: String(resposta).trim() } }];

const original = $('Normalizar mensagem').first().json;
const transcricao = $json.text || $json.transcription || '';
return [{
  json: {
    ...original,
    messageType: 'text',
    text: transcricao || 'Áudio recebido, mas não consegui transcrever com clareza.'
  }
}];

const binary = $binary.data;
const mime = binary?.mimeType || 'image/jpeg';
const base64 = binary?.data || '';
const original = $('Normalizar mensagem').first().json;
return [{ json: { ...original, imageDataUrl: `data:${mime};base64,${base64}` } }];

const content = $json.choices?.[0]?.message?.content || '{}';
let parsed = {};
try {
  parsed = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) {
  parsed = { descricao: content, palavras_chave: content };
}
const termo = Array.isArray(parsed.palavras_chave) ? parsed.palavras_chave.join(' ') : String(parsed.palavras_chave || parsed.descricao || '');
const original = $('Normalizar mensagem').first().json;
return [{ json: { ...original, descricaoImagem: parsed.descricao || termo, termoBusca: termo } }];

const produtos = $input.all().map(i => i.json);
const original = $('Extrair termos da imagem').first().json;

let resposta = `Analisei a imagem e identifiquei: ${original.descricaoImagem || original.termoBusca}.`;
if (produtos.length) {
  resposta += '\n\nProdutos similares encontrados:\n' + produtos.map((p, i) => {
    const preco = p.price !== undefined && p.price !== null ? ` - R$ ${Number(p.price).toFixed(2)}` : '';
    return `${i + 1}. ${p.name}${preco}\n${p.description || ''}`;
  }).join('\n\n');
} else {
  resposta += '\n\nNão encontrei um item similar no catálogo. Posso encaminhar para a equipe verificar?';
}
resposta += '\n\nPosso ajudar em mais alguma coisa?';

return [{ json: { instance: original.instance, remoteJid: original.remoteJid, messageId: original.messageId, resposta } }];

